#!/usr/bin/env python3
"""Logging proxy for Claude API calls, with optional context paging.

Two modes:
    Observe (default):  Logs request/response metrics. Pure observation.
    Compact (--compact): Also evicts stale tool results from the messages
        array before forwarding, replacing them with compact summaries.

Usage:
    # Observation only
    python -m pichay.proxy [--port 0] [--log-dir logs]

    # With context paging
    python -m pichay.proxy --compact [--age-threshold 4] [--min-size 500]

    # Point Claude Code at it
    ANTHROPIC_BASE_URL=http://localhost:<port> claude

Port 0 (default) picks a random free port to avoid collisions.
"""

from __future__ import annotations

import argparse
import json
import os
import socket
import sys
import time
from datetime import datetime, timezone
from pathlib import Path

import httpx
from flask import Flask, Response, request

from pichay.pager import PageStore, compact_messages

ANTHROPIC_API_BASE = "https://api.anthropic.com"


def find_free_port() -> int:
    """Find a free port by binding to port 0 and reading the assignment."""
    with socket.socket(socket.AF_INET6, socket.SOCK_STREAM) as s:
        s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        try:
            # Try IPv6 loopback first (reduces collision space)
            s.bind(("::1", 0))
        except OSError:
            # Fall back to IPv4
            s.close()
            with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s4:
                s4.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
                s4.bind(("127.0.0.1", 0))
                return s4.getsockname()[1]
        return s.getsockname()[1]


def create_app(
    log_dir: Path,
    compact: bool = False,
    age_threshold: int = 4,
    min_size: int = 500,
) -> Flask:
    """Create the proxy Flask app."""
    app = Flask(__name__)
    log_dir.mkdir(parents=True, exist_ok=True)

    # One log file per proxy session
    session_start = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    log_file = log_dir / f"proxy_{session_start}.jsonl"

    # Pager state (lives for the proxy session)
    page_store = None
    if compact:
        page_log = log_dir / f"pages_{session_start}.jsonl"
        page_store = PageStore(log_path=page_log)
        print(
            f"Compact mode: age_threshold={age_threshold}, "
            f"min_size={min_size}",
            file=sys.stderr,
        )
        print(f"Page log: {page_log}", file=sys.stderr)

    # Persistent HTTP client for forwarding
    client = httpx.Client(
        base_url=ANTHROPIC_API_BASE,
        timeout=httpx.Timeout(300.0, connect=30.0),
    )

    def log_record(record: dict) -> None:
        """Append a record to the log file."""
        with open(log_file, "a", encoding="utf-8") as f:
            f.write(json.dumps(record, default=str) + "\n")

    def measure_system_prompt(body: dict) -> dict:
        """Extract system prompt metrics."""
        system = body.get("system", "")
        if isinstance(system, str):
            return {
                "system_prompt_bytes": len(system.encode("utf-8")),
                "system_prompt_type": "string",
                "system_prompt_preview": system[:200],
            }
        elif isinstance(system, list):
            total_bytes = sum(
                len(json.dumps(block).encode("utf-8")) for block in system
            )
            block_types = [
                block.get("type", "unknown")
                for block in system
                if isinstance(block, dict)
            ]
            return {
                "system_prompt_bytes": total_bytes,
                "system_prompt_type": "blocks",
                "system_prompt_block_count": len(system),
                "system_prompt_block_types": block_types,
                "system_prompt_preview": json.dumps(system[0])[:200]
                if system
                else "",
            }
        return {"system_prompt_bytes": 0, "system_prompt_type": "absent"}

    def measure_messages(body: dict) -> dict:
        """Extract message array metrics without storing full content."""
        messages = body.get("messages", [])
        metrics = {
            "message_count": len(messages),
            "messages_total_bytes": len(
                json.dumps(messages).encode("utf-8")
            ),
            "role_counts": {},
            "tool_result_count": 0,
            "tool_result_bytes": 0,
            "tool_use_count": 0,
            "text_bytes": 0,
            "thinking_bytes": 0,
        }

        for msg in messages:
            role = msg.get("role", "unknown")
            metrics["role_counts"][role] = (
                metrics["role_counts"].get(role, 0) + 1
            )

            content = msg.get("content", "")
            if isinstance(content, str):
                metrics["text_bytes"] += len(content.encode("utf-8"))
            elif isinstance(content, list):
                for block in content:
                    if not isinstance(block, dict):
                        continue
                    block_type = block.get("type", "")
                    if block_type == "tool_result":
                        metrics["tool_result_count"] += 1
                        result_content = block.get("content", "")
                        if isinstance(result_content, str):
                            metrics["tool_result_bytes"] += len(
                                result_content.encode("utf-8")
                            )
                        else:
                            metrics["tool_result_bytes"] += len(
                                json.dumps(result_content).encode("utf-8")
                            )
                    elif block_type == "tool_use":
                        metrics["tool_use_count"] += 1
                    elif block_type == "text":
                        metrics["text_bytes"] += len(
                            block.get("text", "").encode("utf-8")
                        )
                    elif block_type == "thinking":
                        metrics["thinking_bytes"] += len(
                            block.get("thinking", "").encode("utf-8")
                        )

        return metrics

    @app.route("/v1/messages", methods=["POST"])
    def proxy_messages():
        """Proxy the messages endpoint with full logging."""
        request_time = datetime.now(timezone.utc)
        body = request.get_json(force=True)

        # Measure without storing full content
        system_metrics = measure_system_prompt(body)
        message_metrics = measure_messages(body)

        request_record = {
            "type": "request",
            "timestamp": request_time.isoformat(),
            "model": body.get("model", "unknown"),
            "max_tokens": body.get("max_tokens"),
            "stream": body.get("stream", False),
            "system": system_metrics,
            "messages": message_metrics,
            "total_request_bytes": len(
                json.dumps(body).encode("utf-8")
            ),
        }

        if body.get("system"):
            request_record["system_prompt_full"] = body["system"]

        log_record(request_record)

        # --- Temperature override (if configured) ---
        # Extended thinking requires temperature=1; skip override when thinking is active.
        # Broad check: any truthy "thinking" field means thinking is requested.
        thinking_enabled = bool(body.get("thinking"))
        if app.config.get("temperature_override") is not None and not thinking_enabled:
            body["temperature"] = app.config["temperature_override"]
        elif app.config.get("temperature_override") is not None and thinking_enabled:
            print(
                f"  [proxy] Skipping temperature override "
                f"(thinking enabled: {body.get('thinking')})",
                file=sys.stderr,
            )

        # --- Context paging (if enabled) ---
        if compact and page_store is not None:
            messages = body.get("messages", [])

            # Detect page faults BEFORE compaction
            faults = page_store.detect_faults(messages)
            if faults:
                for fault in faults:
                    print(
                        f"  PAGE FAULT: {fault.tool_name} "
                        f"re-requested (evicted from turn "
                        f"{fault.original_eviction.turn_index}, "
                        f"{fault.original_eviction.original_size:,} bytes)",
                        file=sys.stderr,
                    )
                log_record({
                    "type": "page_faults",
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                    "count": len(faults),
                    "faults": [
                        {
                            "tool_name": f.tool_name,
                            "original_turn": f.original_eviction.turn_index,
                            "original_size": f.original_eviction.original_size,
                        }
                        for f in faults
                    ],
                    "cumulative_faults": len(page_store.faults),
                    "cumulative_evictions": page_store.cumulative_evictions,
                    "fault_rate": (
                        len(page_store.faults)
                        / page_store.cumulative_evictions
                        if page_store.cumulative_evictions > 0
                        else 0.0
                    ),
                })

            # Compact
            stats = compact_messages(
                messages,
                age_threshold=age_threshold,
                min_size=min_size,
                page_store=page_store,
            )
            if stats.evicted_count > 0:
                post_metrics = measure_messages(body)
                compaction_record = {
                    "type": "compaction",
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                    "evicted": stats.evicted_count,
                    "total_tool_results": stats.total_tool_results,
                    "bytes_before": stats.bytes_before,
                    "bytes_after": stats.bytes_after,
                    "bytes_saved": stats.bytes_saved,
                    "reduction_pct": round(stats.reduction_pct, 1),
                    "skipped_small": stats.skipped_small,
                    "skipped_recent": stats.skipped_recent,
                    "skipped_error": stats.skipped_error,
                    "cumulative_evictions": page_store.cumulative_evictions,
                    "cumulative_bytes_saved": page_store.cumulative_bytes_saved,
                    "cumulative_faults": len(page_store.faults),
                    "fault_rate": round(
                        len(page_store.faults)
                        / page_store.cumulative_evictions
                        * 100,
                        1,
                    )
                    if page_store.cumulative_evictions > 0
                    else 0.0,
                    "messages_bytes_before": message_metrics[
                        "messages_total_bytes"
                    ],
                    "messages_bytes_after": post_metrics[
                        "messages_total_bytes"
                    ],
                }
                log_record(compaction_record)
                print(
                    f"  Compacted: {stats.evicted_count} results, "
                    f"saved {stats.bytes_saved:,} bytes "
                    f"({stats.reduction_pct:.0f}%), "
                    f"cumulative {page_store.cumulative_bytes_saved:,}, "
                    f"faults {len(page_store.faults)}"
                    f"/{page_store.cumulative_evictions}",
                    file=sys.stderr,
                )

        # Forward to Anthropic
        headers = dict(request.headers)
        for h in ["Host", "Content-Length", "Transfer-Encoding"]:
            headers.pop(h, None)

        upstream_path = "/v1/messages"
        if request.query_string:
            upstream_path += "?" + request.query_string.decode("utf-8")

        if body.get("stream", False):
            return _proxy_streaming(body, headers, request_time, upstream_path)
        else:
            return _proxy_direct(body, headers, request_time, upstream_path)

    def _strip_response_headers(raw_headers):
        skip = {
            "transfer-encoding",
            "content-length",
            "content-encoding",
            "connection",
            "keep-alive",
        }
        return {
            k: v
            for k, v in raw_headers.items()
            if k.lower() not in skip
        }

    def _proxy_direct(body, headers, request_time, upstream_path):
        try:
            resp = client.post(
                upstream_path, json=body, headers=headers,
            )
            response_time = datetime.now(timezone.utc)
            try:
                resp_body = resp.json()
                usage = resp_body.get("usage", {})
                log_record({
                    "type": "response",
                    "timestamp": response_time.isoformat(),
                    "duration_ms": int(
                        (response_time - request_time).total_seconds() * 1000
                    ),
                    "status_code": resp.status_code,
                    "usage": usage,
                    "stop_reason": resp_body.get("stop_reason"),
                })
            except Exception:
                log_record({
                    "type": "response_error",
                    "timestamp": response_time.isoformat(),
                    "status_code": resp.status_code,
                })
            return Response(
                resp.content,
                status=resp.status_code,
                headers=_strip_response_headers(resp.headers),
            )
        except Exception as e:
            log_record({
                "type": "proxy_error",
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "error": str(e),
            })
            return Response(
                json.dumps({"error": str(e)}),
                status=502,
                content_type="application/json",
            )

    def _proxy_streaming(body, headers, request_time, upstream_path):
        try:
            resp = client.send(
                client.build_request(
                    "POST", upstream_path, json=body, headers=headers,
                ),
                stream=True,
            )
            response_headers = _strip_response_headers(resp.headers)

            def generate():
                first_byte_time = None
                chunks_collected = []
                try:
                    for chunk in resp.iter_bytes():
                        if first_byte_time is None:
                            first_byte_time = datetime.now(timezone.utc)
                        chunks_collected.append(chunk)
                        yield chunk
                finally:
                    resp.close()
                    response_time = datetime.now(timezone.utc)
                    full_response = b"".join(chunks_collected)

                    usage = {}
                    try:
                        text = full_response.decode("utf-8", errors="replace")
                        for line in reversed(text.split("\n")):
                            if "message_delta" in line and "usage" in line:
                                if line.startswith("data: "):
                                    event_data = json.loads(line[6:])
                                    usage = event_data.get("usage", {})
                                    break
                            elif "message_start" in line and "usage" in line:
                                if line.startswith("data: "):
                                    event_data = json.loads(line[6:])
                                    msg = event_data.get("message", {})
                                    usage = msg.get("usage", {})
                    except Exception:
                        pass

                    log_record({
                        "type": "response_stream",
                        "timestamp": response_time.isoformat(),
                        "duration_ms": int(
                            (response_time - request_time).total_seconds()
                            * 1000
                        ),
                        "first_byte_ms": int(
                            (first_byte_time - request_time).total_seconds()
                            * 1000
                        )
                        if first_byte_time
                        else None,
                        "status_code": resp.status_code,
                        "response_bytes": len(full_response),
                        "usage": usage,
                    })

            return Response(
                generate(),
                status=resp.status_code,
                headers=response_headers,
                content_type=response_headers.get(
                    "content-type", "text/event-stream"
                ),
            )
        except Exception as e:
            log_record({
                "type": "proxy_error",
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "error": str(e),
            })
            return Response(
                json.dumps({"error": str(e)}),
                status=502,
                content_type="application/json",
            )

    @app.route("/health")
    def health():
        result = {
            "status": "ok",
            "mode": "compact" if compact else "observe",
            "log_file": str(log_file),
        }
        if compact and page_store is not None:
            result["pager"] = page_store.summary()
        return result

    print(f"Logging to: {log_file}", file=sys.stderr)
    return app


def main():
    parser = argparse.ArgumentParser(
        description="Logging proxy for Claude API (with optional context paging)"
    )
    parser.add_argument(
        "--port", type=int, default=0,
        help="Port to listen on (0 = random free port, default: 0)",
    )
    parser.add_argument(
        "--log-dir", type=Path, default=Path("logs"),
        help="Directory for proxy logs (default: logs/)",
    )
    parser.add_argument(
        "--compact", action="store_true",
        help="Enable context paging: evict stale tool results",
    )
    parser.add_argument(
        "--age-threshold", type=int, default=4,
        help="Evict tool results older than N user-turns (default: 4)",
    )
    parser.add_argument(
        "--min-size", type=int, default=500,
        help="Don't evict results smaller than N bytes (default: 500)",
    )
    parser.add_argument(
        "--temperature", type=float, default=None,
        help="Override temperature on all requests (e.g., 0 for deterministic)",
    )
    args = parser.parse_args()

    app = create_app(
        args.log_dir,
        compact=args.compact,
        age_threshold=args.age_threshold,
        min_size=args.min_size,
    )
    if args.temperature is not None:
        app.config["temperature_override"] = args.temperature

    port = args.port if args.port != 0 else find_free_port()
    mode = "COMPACT" if args.compact else "OBSERVE"
    print(
        f"Proxy [{mode}] listening on http://localhost:{port}",
        file=sys.stderr,
    )
    print(
        f"Use: ANTHROPIC_BASE_URL=http://localhost:{port} claude",
        file=sys.stderr,
    )
    app.run(host="127.0.0.1", port=port, threaded=True)


if __name__ == "__main__":
    main()

"""Context window pager — evicts stale tool results from the messages array.

This is the intervention layer for the phase 1 context utilization experiment.
It sits between Claude Code and Anthropic's API (inside the proxy) and replaces
old, large tool results with compact summaries. The originals are stored in a
page file for logging and analysis.

Design decisions:
- FIFO eviction: oldest results first (data shows Q1 results have 0.896
  amplification ratio — evicting them captures the most benefit)
- No recall tool injection: if the model needs evicted content, it already
  knows how to re-issue the tool call (Read, Grep, etc.). The "page fault"
  is just a new tool call. PDP-11 overlays, not virtual memory.
- Error results are never evicted (the model needs those for debugging)
- Small results (<min_size bytes) aren't worth compacting

Metrics for success (from Tony):
- Lower token consumption
- Better quality output (fewer tokens → LLMs work better)
- Faster responses
- Slower consumption of the context window
"""

from __future__ import annotations

import json
import time
from dataclasses import dataclass, field
from datetime import datetime, timezone
from pathlib import Path


@dataclass
class PageEntry:
    """A single evicted tool result."""

    tool_use_id: str
    tool_name: str
    tool_input: dict
    original_content: str | list
    original_size: int
    summary: str
    evicted_at: float  # time.monotonic()
    turn_index: int
    turns_from_end: int


@dataclass
class PageFault:
    """A tool call that re-requests evicted content."""

    tool_use_id: str
    tool_name: str
    tool_input: dict
    original_eviction: PageEntry
    detected_at: float  # time.monotonic()


@dataclass
class CompactionStats:
    """What happened during a single compaction pass."""

    total_tool_results: int = 0
    evicted_count: int = 0
    bytes_before: int = 0
    bytes_after: int = 0
    skipped_small: int = 0
    skipped_recent: int = 0
    skipped_error: int = 0

    @property
    def bytes_saved(self) -> int:
        return self.bytes_before - self.bytes_after

    @property
    def reduction_pct(self) -> float:
        if self.bytes_before == 0:
            return 0.0
        return (self.bytes_saved / self.bytes_before) * 100


class PageStore:
    """Stores evicted tool result content and detects page faults.

    In-memory for now. The page file is for analysis, not production.

    A page fault is when the model re-issues a tool call for content
    that was evicted. This is the key observability signal: it tells
    us whether eviction was wrong (costly) or right (content was dead).
    """

    def __init__(self, log_path: Path | None = None):
        self.pages: dict[str, PageEntry] = {}
        self.log_path = log_path
        self.cumulative_bytes_saved: int = 0
        self.cumulative_evictions: int = 0
        self.faults: list[PageFault] = []
        # Index for fault detection: (tool_name, key) → PageEntry
        # Key is the identifying parameter (file_path for Read, etc.)
        self._eviction_index: dict[tuple[str, str], PageEntry] = {}

    def store(self, entry: PageEntry) -> None:
        self.pages[entry.tool_use_id] = entry
        self.cumulative_bytes_saved += entry.original_size - len(
            entry.summary.encode("utf-8")
        )
        self.cumulative_evictions += 1

        # Index for fault detection
        key = _eviction_key(entry.tool_name, entry.tool_input)
        if key is not None:
            self._eviction_index[(entry.tool_name, key)] = entry

        if self.log_path is not None:
            record = {
                "type": "eviction",
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "tool_use_id": entry.tool_use_id,
                "tool_name": entry.tool_name,
                "original_size": entry.original_size,
                "summary_size": len(entry.summary.encode("utf-8")),
                "turn_index": entry.turn_index,
                "turns_from_end": entry.turns_from_end,
            }
            with open(self.log_path, "a", encoding="utf-8") as f:
                f.write(json.dumps(record) + "\n")

    def detect_faults(self, messages: list[dict]) -> list[PageFault]:
        """Scan recent tool_use blocks for re-requests of evicted content.

        Looks at tool_use blocks in assistant messages and checks if any
        match evicted pages. A match means the model needed content we
        took away — a page fault.
        """
        new_faults = []
        for msg in messages:
            if msg.get("role") != "assistant":
                continue
            content = msg.get("content", [])
            if not isinstance(content, list):
                continue
            for block in content:
                if not isinstance(block, dict):
                    continue
                if block.get("type") != "tool_use":
                    continue

                tool_name = block.get("name", "")
                tool_input = block.get("input", {})
                tool_use_id = block.get("id", "")

                # Skip the original tool_use that produced the
                # evicted result — that's not a fault, it's history
                if tool_use_id in self.pages:
                    continue

                key = _eviction_key(tool_name, tool_input)
                if key is None:
                    continue

                evicted = self._eviction_index.get((tool_name, key))
                if evicted is None:
                    continue

                # Don't double-count: check if this tool_use_id
                # was already recorded as a fault
                if any(f.tool_use_id == tool_use_id for f in self.faults):
                    continue

                fault = PageFault(
                    tool_use_id=tool_use_id,
                    tool_name=tool_name,
                    tool_input=tool_input,
                    original_eviction=evicted,
                    detected_at=time.monotonic(),
                )
                new_faults.append(fault)
                self.faults.append(fault)

                if self.log_path is not None:
                    record = {
                        "type": "page_fault",
                        "timestamp": datetime.now(timezone.utc).isoformat(),
                        "tool_name": tool_name,
                        "eviction_key": key,
                        "original_tool_use_id": evicted.tool_use_id,
                        "original_size": evicted.original_size,
                        "original_turn": evicted.turn_index,
                    }
                    with open(self.log_path, "a", encoding="utf-8") as f:
                        f.write(json.dumps(record) + "\n")

        return new_faults

    def retrieve(self, tool_use_id: str) -> PageEntry | None:
        return self.pages.get(tool_use_id)

    def summary(self) -> dict:
        """Current state for the health endpoint."""
        return {
            "total_evictions": self.cumulative_evictions,
            "total_bytes_saved": self.cumulative_bytes_saved,
            "total_page_faults": len(self.faults),
            "fault_rate": (
                len(self.faults) / self.cumulative_evictions
                if self.cumulative_evictions > 0
                else 0.0
            ),
            "pages_in_store": len(self.pages),
            "faults_by_tool": _count_by(
                self.faults, lambda f: f.tool_name
            ),
            "evictions_by_tool": _count_by(
                list(self.pages.values()), lambda p: p.tool_name
            ),
        }


def _count_by(items: list, key_fn) -> dict[str, int]:
    counts: dict[str, int] = {}
    for item in items:
        k = key_fn(item)
        counts[k] = counts.get(k, 0) + 1
    return counts


def _eviction_key(tool_name: str, tool_input: dict) -> str | None:
    """Extract the identifying key for a tool call, for fault matching.

    Returns None for tools where re-invocation isn't meaningful
    (e.g., Agent results can't be re-requested by input match).
    """
    if tool_name == "Read":
        return tool_input.get("file_path")
    elif tool_name == "Grep":
        # pattern + path is the identity
        pattern = tool_input.get("pattern", "")
        path = tool_input.get("path", ".")
        return f"{pattern}@{path}"
    elif tool_name == "Glob":
        return tool_input.get("pattern")
    elif tool_name == "Bash":
        return tool_input.get("command")
    elif tool_name == "WebFetch":
        return tool_input.get("url")
    elif tool_name == "WebSearch":
        return tool_input.get("query")
    return None


def _content_size(content: str | list | None) -> int:
    """Measure content size in bytes."""
    if content is None:
        return 0
    if isinstance(content, str):
        return len(content.encode("utf-8"))
    return len(json.dumps(content).encode("utf-8"))


def _build_tool_use_index(messages: list[dict]) -> dict[str, dict]:
    """Map tool_use_id → {name, input} from assistant messages."""
    index = {}
    for msg in messages:
        if msg.get("role") != "assistant":
            continue
        content = msg.get("content", [])
        if not isinstance(content, list):
            continue
        for block in content:
            if isinstance(block, dict) and block.get("type") == "tool_use":
                index[block["id"]] = {
                    "name": block.get("name", "unknown"),
                    "input": block.get("input", {}),
                }
    return index


def _make_summary(tool_name: str, tool_input: dict, original_size: int,
                  original_content: str | list | None = None) -> str:
    """Generate a compact summary for an evicted tool result.

    The summary tells the model what WAS here and how to get it back
    (re-issue the same tool call). No magic — just information.
    """
    size_str = f"{original_size:,}"

    if tool_name == "Read":
        path = tool_input.get("file_path", "unknown")
        line_count = ""
        if isinstance(original_content, str):
            lines = original_content.count("\n")
            line_count = f", {lines} lines"
        return (
            f"[Paged out: Read {path} ({size_str} bytes{line_count}). "
            f"Re-read the file if you need its content.]"
        )

    elif tool_name == "Grep":
        pattern = tool_input.get("pattern", "?")
        path = tool_input.get("path", ".")
        mode = tool_input.get("output_mode", "files_with_matches")
        # Count result lines if string content
        match_info = ""
        if isinstance(original_content, str):
            result_lines = len(original_content.strip().splitlines())
            match_info = f", {result_lines} result lines"
        return (
            f"[Paged out: Grep '{pattern}' in {path} "
            f"(mode={mode}{match_info}, {size_str} bytes). "
            f"Re-run the search if you need results.]"
        )

    elif tool_name == "Glob":
        pattern = tool_input.get("pattern", "?")
        match_info = ""
        if isinstance(original_content, str):
            matches = len(original_content.strip().splitlines())
            match_info = f", {matches} matches"
        return (
            f"[Paged out: Glob '{pattern}'{match_info} ({size_str} bytes). "
            f"Re-run if you need the file list.]"
        )

    elif tool_name == "Bash":
        cmd = tool_input.get("command", "?")
        # Truncate long commands
        if len(cmd) > 120:
            cmd = cmd[:117] + "..."
        return (
            f"[Paged out: Bash `{cmd}` ({size_str} bytes). "
            f"Re-run the command if you need its output.]"
        )

    elif tool_name == "WebFetch":
        url = tool_input.get("url", "?")
        return (
            f"[Paged out: WebFetch {url} ({size_str} bytes). "
            f"Re-fetch if you need the content.]"
        )

    elif tool_name == "WebSearch":
        query = tool_input.get("query", "?")
        return (
            f"[Paged out: WebSearch '{query}' ({size_str} bytes). "
            f"Re-search if you need results.]"
        )

    elif tool_name in ("Agent", "TaskOutput"):
        return (
            f"[Paged out: {tool_name} result ({size_str} bytes). "
            f"Content was consumed when originally returned.]"
        )

    else:
        return (
            f"[Paged out: {tool_name} ({size_str} bytes). "
            f"Re-invoke the tool if you need this content.]"
        )


def compact_messages(
    messages: list[dict],
    age_threshold: int = 4,
    min_size: int = 500,
    page_store: PageStore | None = None,
) -> CompactionStats:
    """Replace old, large tool results with compact summaries.

    Mutates the messages list in place. Returns stats about what was done.

    Args:
        messages: The messages array from the API request body.
        age_threshold: Results older than this many user-turns from the
            end get evicted. Default 4.
        min_size: Results smaller than this (bytes) are kept as-is.
            Not worth compacting a 22-byte Edit confirmation. Default 500.
        page_store: If provided, evicted content is stored here.
    """
    stats = CompactionStats()
    tool_use_index = _build_tool_use_index(messages)

    # Count user turns (each user message is a "turn")
    user_turn_indices: list[int] = []
    for i, msg in enumerate(messages):
        if msg.get("role") == "user":
            user_turn_indices.append(i)

    total_user_turns = len(user_turn_indices)

    # Walk through messages and compact old tool results
    current_user_turn = 0
    for msg_idx, msg in enumerate(messages):
        if msg.get("role") != "user":
            continue

        current_user_turn += 1
        turns_from_end = total_user_turns - current_user_turn

        content = msg.get("content", [])
        if not isinstance(content, list):
            continue

        for block_idx, block in enumerate(content):
            if not isinstance(block, dict):
                continue
            if block.get("type") != "tool_result":
                continue

            stats.total_tool_results += 1
            original_content = block.get("content", "")
            original_size = _content_size(original_content)

            # Skip errors — model needs those
            if block.get("is_error", False):
                stats.skipped_error += 1
                continue

            # Skip recent results
            if turns_from_end < age_threshold:
                stats.skipped_recent += 1
                stats.bytes_before += original_size
                stats.bytes_after += original_size
                continue

            # Skip small results
            if original_size < min_size:
                stats.skipped_small += 1
                stats.bytes_before += original_size
                stats.bytes_after += original_size
                continue

            # This result gets evicted
            tool_use_id = block.get("tool_use_id", "")
            tool_info = tool_use_index.get(tool_use_id, {})
            tool_name = tool_info.get("name", "unknown")
            tool_input = tool_info.get("input", {})

            summary = _make_summary(
                tool_name, tool_input, original_size, original_content
            )

            # Store the original
            if page_store is not None:
                entry = PageEntry(
                    tool_use_id=tool_use_id,
                    tool_name=tool_name,
                    tool_input=tool_input,
                    original_content=original_content,
                    original_size=original_size,
                    summary=summary,
                    evicted_at=time.monotonic(),
                    turn_index=current_user_turn,
                    turns_from_end=turns_from_end,
                )
                page_store.store(entry)

            # Replace the content
            content[block_idx] = {**block, "content": summary}

            stats.evicted_count += 1
            stats.bytes_before += original_size
            stats.bytes_after += len(summary.encode("utf-8"))

    return stats

